mapper.select:
SELECT v.database_id AS databaseId, v.table_name AS tableName, MAX(CASE WHEN v.session_trigger = 'manual' THEN v.collected_at END) AS lastVacuum, MAX(CASE WHEN v.session_trigger = 'autovacuum' THEN v.collected_at END) AS lastAutovacuum, AVG(v.n_dead_tup) AS deadTuples, AVG(v.n_mod_since_analyze) AS modSinceAnalyze, AVG(v.bloat_ratio) AS bloatRatio, COUNT(CASE WHEN v.session_trigger = 'manual' AND v.collected_at >= NOW() - INTERVAL '24 hours' THEN 1 END) AS vacuumCount24h, COUNT(CASE WHEN v.session_trigger = 'autovacuum' AND v.collected_at >= NOW() - INTERVAL '24 hours' THEN 1 END) AS autovacuumCount24h FROM vacuum_raw_metrics v WHERE v.collected_at BETWEEN #{start} AND #{end}
AND v.database_id = #{databaseId, jdbcType=BIGINT}
GROUP BY v.database_id, v.table_name ORDER BY MAX(v.collected_at) DESC LIMIT 100
